Port.App<T>() is the mandatory first call when using the [Port] attribute-based initialization style. Decorate your application class with [Port] to declare the repository name and pull path, then call Port.App<T>() before any other Port API. [Port("sample")] public class SampleApp { } // In startup (e.g. constructor or Program.cs) — must be called first Port.App<SampleApp>(); Port.App<T>() reads the [Port] attribute on T, creates the repository via Port.Repository.New(pullPath, reponame), and starts the PortDic instance. All subsequent Port.Push, Port.Pull, and Port.Repository.Load calls depend on this initialization being completed. Full Startup Example​ [Port("sample")] public partial class MainWindow : Window { public MainWindow() { InitializeComponent(); try { Port.App<MainWindow>(); #if DEBUG var ioDoc = Port.Document<IOModel>(@"C:\Users\admin\Documents\IO.docx"); ioDoc.Where(v => v.Key.Contains("OnOff")).ToList() .ForEach(v => v.DataType = "Enum.OnOff"); ioDoc.Where(v => v.Key.Contains("Temp")).ToList() .ForEach(v => v.DataType = "f8"); if (ioDoc.Count > 0) { ioDoc.New(@"C:\Users\admin\Documents\sample\.page\io.page"); ioDoc.New(@"C:\Users\admin\Documents\sample\.net\io.cs"); } Port.Push("sample", new CustomEFEM()); Port.Push("sample", ioDoc.NewPage("Device")); Port.Pull("sample", @"D:\PORT\SampleArduinoLib\sample\Repo\pull"); #endif Port.Add<LoadportController, LoadportModel>("LP1"); Port.Add<LoadportController, LoadportModel>("LP2"); Port.OnReady += Port_OnReady; Port.Run(); } catch (Exception ex) { MessageBox.Show( $"{ex.Message}

Inner: {ex.InnerException?.Message}

Stack: {ex.StackTrace}"); } } }
